namespace sv_52457d979b1045d3b759c349aee8777b.Services;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class Notification
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

public class NotificationHub
{
    private readonly List<Notification> _notifications = [];
    private readonly Lock _lock = new();

    public event Action? OnChange;

    public IReadOnlyList<Notification> Notifications
    {
        get
        {
            lock (_lock) return _notifications.ToList();
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock) return _notifications.Count(n => !n.IsRead);
    }

    public void AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Insert(0, new Notification
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        OnChange?.Invoke();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var notification = _notifications.FirstOrDefault(n => n.Id == id);
            if (notification is not null)
                notification.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications)
                n.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        OnChange?.Invoke();
    }
}

namespace sv_52457d979b1045d3b759c349aee8777b.Services;

public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private static readonly string[] Titles =
    [
        "Server CPU spike", "Deployment complete", "Disk space low",
        "New user signup", "Payment failed", "Backup succeeded",
        "Certificate expiring", "Rate limit exceeded", "Health check failed"
    ];
    private static readonly string[] Messages =
    [
        "Requires immediate attention.", "Completed successfully.",
        "Review within 24 hours.", "No action needed.",
        "Escalate to on-call engineer."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_cts is not null) return;
        _cts = new CancellationTokenSource();
        _ = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _timer = null;
        _cts?.Dispose();
        _cts = null;
    }

    private async Task RunAsync(CancellationToken ct)
    {
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        try
        {
            while (await _timer.WaitForNextTickAsync(ct))
            {
                var rand = Random.Shared;
                var title = Titles[rand.Next(Titles.Length)];
                var message = Messages[rand.Next(Messages.Length)];
                var severity = (Severity)rand.Next(3);
                _hub.AddNotification(title, message, severity);
            }
        }
        catch (OperationCanceledException) { }
    }

    public void Dispose()
    {
        Stop();
    }
}

