@rendermode InteractiveServer
@inject NotificationHub Hub
@implements IDisposable

<div class="notification-bell position-relative d-inline-block px-3 py-2">
    <a href="notifications" class="text-white text-decoration-none">
        <span class="bi bi-bell-fill" aria-hidden="true">🔔</span>
        @if (_unreadCount > 0)
        {
            <span class="badge bg-danger rounded-pill position-absolute top-0 start-100 translate-middle">
                @_unreadCount
            </span>
        }
    </a>
</div>

@code {
    private int _unreadCount;
    private Action? _handler;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        _handler = () => InvokeAsync(() =>
        {
            _unreadCount = Hub.GetUnreadCount();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@inject NotificationHub Hub
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h3>Notifications</h3>

<div class="mb-3">
    <button class="btn btn-outline-primary" @onclick="MarkAllRead">Mark All Read</button>
</div>

@foreach (var group in GetGroupedNotifications())
{
    <h5 class="mt-4">
        <span class="badge @GetBadgeClass(group.Key)">@group.Key</span>
    </h5>
    <ul class="list-group mb-3">
        @foreach (var n in group)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start @(n.IsRead ? "" : "list-group-item-light fw-bold")">
                <div class="ms-2 me-auto">
                    <div class="fw-semibold">@n.Title</div>
                    <small>@n.Message</small>
                    <br /><small class="text-muted">@n.Timestamp.ToString("g")</small>
                </div>
                <div class="btn-group btn-group-sm">
                    @if (!n.IsRead)
                    {
                        <button class="btn btn-outline-success" @onclick="() => MarkRead(n.Id)">Mark Read</button>
                    }
                    <button class="btn btn-outline-danger" @onclick="() => Dismiss(n.Id)">Dismiss</button>
                </div>
            </li>
        }
    </ul>
}

@if (!Hub.Notifications.Any())
{
    <p class="text-muted">No notifications.</p>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        Hub.OnChange += _handler;
    }

    private IEnumerable<IGrouping<Severity, Notification>> GetGroupedNotifications()
    {
        return Hub.Notifications
            .OrderBy(n => n.Severity == Severity.Critical ? 0 : n.Severity == Severity.Warning ? 1 : 2)
            .GroupBy(n => n.Severity);
    }

    private void MarkRead(Guid id) => Hub.MarkAsRead(id);
    private void MarkAllRead() => Hub.MarkAllRead();
    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private static string GetBadgeClass(Severity severity) => severity switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning => "bg-warning text-dark",
        _ => "bg-info text-dark"
    };

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

